له',128,'617'),('محمد احمد السيدعبدالله السيدموسى الهاشمىالامارات',219,'611'),('امل يوسف محمد بوالصفارد البلوشى',115,'617'),('أحلام يوسف محمد بوالصفارد البلوشى',115,'617'),('طلال يوسف محمد بوالصفارد البلوشى',115,'606'),('حميد عبدالله محمد عيسى الهاشمى',115,'606'),('حسن على ابراهيم محمد البلوشى',115,'606'),('ساره السيد يوسف السيد حسن الهاشمى',255,'612'),('احمد عبدالله محمد البلوشى',109,'606'),('خالد محمود السيدعبدالله السيدموسى الهاشمى',255,'612'),('احمد على راشد ربيع الشحى',206,'618'),('سعيد محمود السيد عبدالله الهاشمى',255,'612'),('على ابراهيم راشد بن تون الغافرى',206,'618'),('محمد حسن على الخوار الشحى',235,'618'),('محمد مراد عبدالله ابراهيم الرئيسى',128,'619'),('سلطان احمد يوسف الرئيسى',124,'625'),('حمدان محمد مراد عبدالله الرئيسى',128,'619'),('فاطمه حسين ابراهيم عبدالله',124,'625'),('خالد وليد على بن فلاح المنصورى',185,'619'),('عبدالله سالم عبدالله سالم المهيرى',106,'626'),('مريم سالم محمد بالعبد ال على',106,'626'),('شهد على حسن احمد المرزوقى',110,'620'),('منى سالم عبدالله سالم المهيرى',106,'626'),('افنان حسن احمد حسن المرزوقى',110,'620'),('نوره على راشد ربيع الشحى',206,'627'),('فاطمه على راشد ربيع الشحى',206,'627'),('حنان احمد عبدالله عبدالرحمن العلى',116,'621'),('عواطف محمد راشد الطوب الشميلى',206,'627'),('حمدان مروان سبيل حسين البلوشى',116,'621'),('نوف احمد عبدالله عبدالرحمن العلى',116,'621'),('على راشد خميس برشود الحمودى',315,'628'),('على صالح يوسف الحمادى',114,'628'),('مريم على احمد المرزوقى',110,'622'),('عبدالله على حمود راشد الزيودى',315,'628'),('بدريه حسن احمد حسن المرزوقى',110,'622'),('عمران حسن احمد حسن المرزوقى',110,'622'),('سلطان محمد حاجى حاجونى الزرعونى',205,'629'),('فاطمه ابراهيم حسن النمر الزرعونى',205,'629'),('محمد على سلمان المرزوقى',136,'623'),('محمد على محمد منصور المرزوقى',136,'623'),('مريم محمد على سلمان المرزوقى',136,'623'),('ايمان سالم سلطان بونواس الكتبى',191,'624'),('راشد محمد سالم خلفان السويدى',191,'624')) AS pr(full_name, group_number, room_number)
JOIN pilgrims p ON p.full_name = pr.full_name
JOIN groups g ON g.id = p.group_id AND g.group_number = pr.group_number::int
LEFT JOIN housing_assignments ha ON ha.pilgrim_id = p.id AND ha.is_current = true
LEFT JOIN rooms r_db ON r_db.id = ha.room_id
WHERE r_db.room_number IS DISTINCT FROM pr.room_number
LIMIT 50;